.darma-loader-darma-custom-099 {
  width: 40px;
  height: 20px;
  background: var(--loader-color, #ffa500);
  position: relative;
  animation: darma-loader-darma-custom-099-l19-0 1.5s infinite linear;
}
.darma-loader-darma-custom-099:before,
.darma-loader-darma-custom-099:after {
   content:"";
   position: absolute;
   background: inherit; 
   bottom: 100%;
   width: 50%;
   height: 100%;
   animation: inherit;
   animation-name: darma-loader-darma-custom-099-l19-1;
}
.darma-loader-darma-custom-099:before {
  left:0;
  --s:-1,1;
}
.darma-loader-darma-custom-099:after {
  right:0;
}
@keyframes darma-loader-darma-custom-099-l19-0 {
   0%,30%   {transform:translateY(0)     scaleY(1)}
   49.99%   {transform:translateY(-50%)  scaleY(1)}
   50%      {transform:translateY(-50%)  scaleY(-1)}
   70%,100% {transform:translateY(-100%) scaleY(-1)}
}
@keyframes darma-loader-darma-custom-099-l19-1 {
   0%,10%,90%,100% {transform: scale(var(--s,1)) translate(0)}
   30%,70%         {transform: scale(var(--s,1)) translate(20px)}
   50%             {transform: scale(var(--s,1)) translate(20px,20px)}
}

